from django.test import SimpleTestCase
from django.core.exceptions import ValidationError
from django.contrib.auth.validators import ASCIIUsernameValidator, UnicodeUsernameValidator

class UsernameValidatorTests(SimpleTestCase):
    def setUp(self):
        self.ascii_validator = ASCIIUsernameValidator()
        self.unicode_validator = UnicodeUsernameValidator()

    def test_username_validation_with_trailing_newline(self):
        # Valid username
        valid_username = "valid_user"
        self.ascii_validator(valid_username)  # Should not raise
        self.unicode_validator(valid_username)  # Should not raise

        # Invalid username with trailing newline
        invalid_username = "invalid_user\n"
        # This should NOT raise ValidationError if the bug is present
        try:
            self.ascii_validator(invalid_username)  # Should not raise
        except ValidationError:
            self.fail("ASCIIUsernameValidator raised ValidationError for username with trailing newline")

        try:
            self.unicode_validator(invalid_username)  # Should not raise
        except ValidationError:
            self.fail("UnicodeUsernameValidator raised ValidationError for username with trailing newline")

        # Invalid username with multiple trailing newlines
        invalid_username_multiple_newlines = "invalid_user\n\n"
        # This should NOT raise ValidationError if the bug is present
        try:
            self.ascii_validator(invalid_username_multiple_newlines)  # Should not raise
        except ValidationError:
            self.fail("ASCIIUsernameValidator raised ValidationError for username with multiple trailing newlines")

        try:
            self.unicode_validator(invalid_username_multiple_newlines)  # Should not raise
        except ValidationError:
            self.fail("UnicodeUsernameValidator raised ValidationError for username with multiple trailing newlines")
